#include<bits/stdc++.h>
using namespace std;
constexpr int N=400010;
int n,m,q;
int fa_bcj[N],u[N],v[N],p[N],root[N];
vector<int> mp[N];
struct edge
{
    int u,v,w;
    bool operator<(const edge&b)const
    {
        return w<b.w;
    }
}e[N];
int find(int x)
{
    return(x==fa_bcj[x]?x:fa_bcj[x]=find(fa_bcj[x]));
}
struct tree
{
    int ldfn[N],rdfn[N],dfncnt,val[N],rnk[N],fa[N][21];
    void dfs(int x,int f=0)
    {
        if(x<=n)
        {
            ldfn[x]=++dfncnt;
            rnk[dfncnt]=x;
            val[x]=x;
        }
        else
        {
            ldfn[x]=dfncnt+1;
        }
        fa[x][0]=f;
        for(int i=1;i<=20;i++)
        {
            fa[x][i]=fa[fa[x][i-1]][i-1];
        }
        for(int i:mp[x])
        {
            if(i!=f)
            {
                dfs(i,x);
            }
        }
        rdfn[x]=dfncnt;
    }
    int findpre(int x,int y)
    {
        for(int i=20;i>=0;i--)
        {
            if(val[fa[x][i]]>=y&&fa[x][i])
            {
                x=fa[x][i];
            }
        }
        return x;
    }
    int findnxt(int x,int y)
    {
        for(int i=20;i>=0;i--)
        {
            if(val[fa[x][i]]<=y&&fa[x][i])
            {
                x=fa[x][i];
            }
        }
        return x;
    }
    void solve(int op)
    {
        for(int i=1;i<=n*2;i++)
        {
            fa_bcj[i]=i;
            mp[i].clear();
        }
        int tot=n;
        for(int i=1;i<=m;i++)
        {
            if(op==1)
            {
                e[i]=(edge){u[i],v[i],-min(u[i],v[i])};
            }
            if(op==2)
            {
                e[i]=(edge){u[i],v[i],max(u[i],v[i])};
            }
        }
        sort(e+1,e+1+m);
        for(int i=1;i<=m;i++)
        {
            int a=find(e[i].u),b=find(e[i].v);
            if(a!=b)
            {
                fa_bcj[a]=fa_bcj[b]=++tot;
                val[tot]=abs(e[i].w);
                mp[tot].push_back(a);
                mp[tot].push_back(b);
            }
        }
        dfs(tot);
    }
}t1,t2;
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum;
    }a[N*15];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=a[a[x].lson].sum+a[a[x].rson].sum;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=0;
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    long long add(long long x,long long p,long long v)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return x;
        }
        long long now=++cnt;
        a[now]=a[x];
        if(a[x].l==a[x].r)
        {
            a[now].sum+=v;
            return now;
        }
        a[now].lson=add(a[x].lson,p,v);
        a[now].rson=add(a[x].rson,p,v);
        pushup(now);
        return now;
    }
    long long query(long long u,long long v,long long l,long long r)
    {
        if(a[u].l>r||a[u].r<l)
        {
            return 0;
        }
        if(l<=a[u].l&&a[u].r<=r)
        {
            return a[v].sum-a[u].sum;
        }
        return query(a[u].lson,a[v].lson,l,r)+query(a[u].rson,a[v].rson,l,r);
    }
}t;
int main()
{
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&u[i],&v[i]);
        u[i]++,v[i]++;
    }
    t1.solve(1);
    t2.solve(2);
    for(int i=1;i<=n;i++)
    {
        p[t1.rnk[i]]=i;
    }
    root[0]=t.init(1,n);
    for(int i=1;i<=n;i++)
    {
        root[i]=t.add(root[i-1],p[t2.rnk[i]],1);
    }
    while(q--)
    {
        int s,t,l,r;
        scanf("%d%d%d%d",&s,&t,&l,&r);
        s++,t++,l++,r++;
        int x=t1.findpre(s,l);
        int y=t2.findnxt(t,r);
        if(::t.query(root[t2.ldfn[y]-1],root[t2.rdfn[y]],t1.ldfn[x],t1.rdfn[x]))
        {
            printf("1\n");
        }
        else
        {
            printf("0\n");
        }
    }
    return 0;
}
